noncompliant:
// Noncompliant: GNU extension ternary operator with omitted second operand
int result = condition ? : defaultValue;

// Noncompliant: Case ranges in switch statements
switch(value) {
  case 1...5: // GNU extension
    doSomething();
    break;
}

// Noncompliant: Array initializer without =
int arr[] = { [0] 10, [1] 20 };

compliant:
// Compliant: Standard C ternary operator
int result = condition ? condition : defaultValue;

// Compliant: Standard switch statement
switch(value) {
  case 1:
  case 2:
  case 3:
  case 4:
  case 5:
    doSomething();
    break;
}

// Compliant: Standard array initializer
int arr[] = { [0] = 10, [1] = 20 };
